namespace sv_928a8b703c044557970bc478c4fce0d6.Models;

// Service contract records
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(FullName) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone) &&
        !string.IsNullOrWhiteSpace(Address);

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Company) &&
        !string.IsNullOrWhiteSpace(Title) &&
        StartDate.HasValue;

    public WorkEntry ToRecord() => new(Company, Title, StartDate!.Value, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Name) &&
        !string.IsNullOrWhiteSpace(Relationship) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone);

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var status = step == CurrentStep ? "active"
                   : step < CurrentStep ? "completed"
                   : "upcoming";

        <button class="step @status"
                disabled="@(step > CurrentStep)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(step == CurrentStep ? "step" : null)">
            <span class="step-number">
                @if (step < CurrentStep)
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Count - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<fieldset class="work-entry-card">
    <legend>Position @(Index + 1)</legend>

    @if (CanRemove)
    {
        <button type="button" class="btn-remove" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
    }

    <div class="form-row">
        <div class="form-group">
            <label>Company Name *</label>
            <input type="text" @bind="Entry.Company" @bind:event="oninput" placeholder="Company name" />
        </div>
        <div class="form-group">
            <label>Job Title *</label>
            <input type="text" @bind="Entry.Title" @bind:event="oninput" placeholder="Job title" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" @bind="Entry.StartDate" />
        </div>
        <div class="form-group">
            <label>
                <input type="checkbox" @bind="Entry.IsCurrent" />
                Currently working here
            </label>
            @if (!Entry.IsCurrent)
            {
                <label>End Date</label>
                <input type="date" @bind="Entry.EndDate" />
            }
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @bind="Entry.Description" @bind:event="oninput"
                  placeholder="Describe your responsibilities and achievements"></textarea>
    </div>
</fieldset>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<fieldset class="reference-card">
    <legend>Reference @(Index + 1)</legend>

    @if (CanRemove)
    {
        <button type="button" class="btn-remove" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
    }

    <div class="form-row">
        <div class="form-group">
            <label>Name *</label>
            <input type="text" @bind="Reference.Name" @bind:event="oninput" placeholder="Full name" />
        </div>
        <div class="form-group">
            <label>Relationship *</label>
            <input type="text" @bind="Reference.Relationship" @bind:event="oninput" placeholder="e.g., Former Manager" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Email *</label>
            <input type="email" @bind="Reference.Email" @bind:event="oninput" placeholder="email@example.com" />
        </div>
        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" @bind="Reference.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
    </div>
</fieldset>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

