@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var status = step == CurrentStep ? "active"
                   : step < CurrentStep ? "completed"
                   : "upcoming";

        <button class="step @status"
                disabled="@(step > CurrentStep)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(step == CurrentStep ? "step" : null)">
            <span class="step-number">
                @if (step < CurrentStep)
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Count - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];
}

