@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<div class="step-content">
    <h2>Personal Information</h2>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="validation-error">@_error</div>
    }

    <div class="form-row">
        <div class="form-group">
            <label>Full Name *</label>
            <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        </div>
        <div class="form-group">
            <label>Email *</label>
            <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
            @if (_emailError is not null)
            {
                <span class="field-error">@_emailError</span>
            }
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
        <div class="form-group">
            <label>Address *</label>
            <input type="text" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
        </div>
    </div>

    <div class="step-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
            @if (_validating)
            {
                <span>Validating...</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? _error;
    private string? _emailError;
    private bool _validating;

    private async Task HandleNext()
    {
        _error = null;
        _emailError = null;

        if (!Model.IsValid())
        {
            _error = "Please fill in all required fields.";
            return;
        }

        _validating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            _validating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<div class="step-content">
    <h2>Work History</h2>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="validation-error">@_error</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       CanRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _error = null;
        if (!Entries.All(e => e.IsValid()))
        {
            _error = "Please fill in company, title, and start date for all positions.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<div class="step-content">
    <h2>References</h2>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="validation-error">@_error</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       CanRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _error = null;
        if (References.Count < 2)
        {
            _error = "Please provide at least 2 references.";
            return;
        }
        if (!References.All(r => r.IsValid()))
        {
            _error = "Please fill in all fields for each reference.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply

<div class="step-content">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea class="cover-letter-textarea"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="CoverLetter"
                  @bind:event="oninput"
                  @bind:after="NotifyChanged"
                  placeholder="Tell us why you're a great fit for this position..."></textarea>
        <div class="char-count @(CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @CoverLetter.Length / @MaxLength characters
        </div>
    </div>

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<div class="step-content">
    <h2>Review & Submit</h2>

    @if (_submitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p>Your application has been received. Your application ID is <strong>#@_applicationId</strong>.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="validation-error">@_error</div>
        }

        <section class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl class="review-details">
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="review-dates">
                        @entry.StartDate?.ToString("MMM yyyy")
                        &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="review-description">@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var reference in References)
            {
                <div class="review-entry">
                    <strong>@reference.Name</strong> — @reference.Relationship
                    <br />
                    @reference.Email | @reference.Phone
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <p class="review-cover-letter">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(No cover letter provided)" : CoverLetter)</p>
        </section>

