@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<div class="step-content">
    <h2>References</h2>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="validation-error">@_error</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       CanRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _error = null;
        if (References.Count < 2)
        {
            _error = "Please provide at least 2 references.";
            return;
        }
        if (!References.All(r => r.IsValid()))
        {
            _error = "Please fill in all fields for each reference.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

