@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply

<div class="step-content">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea class="cover-letter-textarea"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="CoverLetter"
                  @bind:event="oninput"
                  @bind:after="NotifyChanged"
                  placeholder="Tell us why you're a great fit for this position..."></textarea>
        <div class="char-count @(CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @CoverLetter.Length / @MaxLength characters
        </div>
    </div>

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}

@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models

<div class="step-content">
    <h2>Review & Submit</h2>

    @if (_submitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p>Your application has been received. Your application ID is <strong>#@_applicationId</strong>.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="validation-error">@_error</div>
        }

        <section class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl class="review-details">
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="review-dates">
                        @entry.StartDate?.ToString("MMM yyyy")
                        &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="review-description">@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var reference in References)
            {
                <div class="review-entry">
                    <strong>@reference.Name</strong> — @reference.Relationship
                    <br />
                    @reference.Email | @reference.Phone
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <p class="review-cover-letter">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(No cover letter provided)" : CoverLetter)</p>
        </section>

        <div class="step-actions">
            <button class="btn btn-outline" @onclick="OnBack">Back</button>
            <button class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@_submitting">
                @(_submitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEdit { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool _submitting;
    private bool _submitted;
    private int _applicationId;
    private string? _error;

    private async Task HandleSubmit()
    {
        _error = null;
        _submitting = true;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            _submitting = false;
        }
    }
}

