@page "/apply"
@rendermode InteractiveServer
@namespace sv_928a8b703c044557970bc478c4fce0d6.Components.Pages.Apply
@using sv_928a8b703c044557970bc478c4fce0d6.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="_currentStep" OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep Model="_personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="_references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="_personalInfo"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="_coverLetter"
                        ApplicationService="ApplicationService"
                        OnBack="PreviousStep"
                        OnEdit="GoToStep" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private PersonalInfoModel _personalInfo = new();
    private List<WorkEntryModel> _workEntries = [new()];
    private List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void NextStep() => _currentStep++;

    private void PreviousStep() => _currentStep--;

    private void GoToStep(int step)
    {
        if (step <= _currentStep)
        {
            _currentStep = step;
        }
    }
}

/* ── Layout ── */
.apply-container {
    max-width: 800px;
    margin: 2rem auto;
    padding: 0 1.5rem;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.apply-container h1 {
    text-align: center;
    margin-bottom: 2rem;
    color: #1a1a2e;
}

/* ── Step Indicator ── */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    gap: 0;
    flex-wrap: wrap;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.5rem 0.75rem;
    min-width: 90px;
    transition: opacity 0.2s;
}

.step:disabled {
    cursor: default;
}

.step-number {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    margin-bottom: 0.4rem;
    transition: all 0.2s;
}

.step.active .step-number {
    background: #4361ee;
    color: #fff;
}

.step.completed .step-number {
    background: #2dc653;
    color: #fff;
}

.step.upcoming .step-number {
    background: #e0e0e0;
    color: #999;
}

.checkmark {
    font-size: 1.1rem;
}

.step-label {
    font-size: 0.75rem;
    color: #666;
    text-align: center;
    white-space: nowrap;
}

.step.active .step-label {
    color: #4361ee;
    font-weight: 600;
}

.step.completed .step-label {
    color: #2dc653;
}

.step-connector {
    width: 40px;
    height: 2px;
    background: #e0e0e0;
    margin-bottom: 1.2rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #2dc653;
}

/* ── Step Content ── */
.step-content {
    background: #fff;
    border: 1px solid #e8e8e8;
    border-radius: 12px;
    padding: 2rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
}

.step-content h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    color: #1a1a2e;
    font-size: 1.4rem;
}

/* ── Forms ── */
.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
    margin-bottom: 1rem;
}

@media (max-width: 600px) {
    .form-row {
        grid-template-columns: 1fr;
    }
}

.form-group {
    display: flex;
    flex-direction: column;
    margin-bottom: 0.75rem;
}

.form-group label {
    font-size: 0.85rem;
    font-weight: 500;
    color: #444;
    margin-bottom: 0.3rem;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    padding: 0.6rem 0.75rem;
    border: 1px solid #d0d0d0;
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.2s;
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: #4361ee;
    box-shadow: 0 0 0 3px rgba(67, 97, 238, 0.1);
}

.form-group input[type="checkbox"] {
    margin-right: 0.4rem;
}

/* ── Validation ── */
.validation-error {
    background: #fee;
    border: 1px solid #fcc;
    color: #c0392b;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

.field-error {
    color: #c0392b;
    font-size: 0.8rem;
    margin-top: 0.2rem;
}

/* ── Cards (work entries, references) ── */
.work-entry-card,
.reference-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
    margin-bottom: 1rem;
    position: relative;
    background: #fafafa;
}

.work-entry-card legend,
.reference-card legend {
    font-weight: 600;
    color: #444;
    padding: 0 0.5rem;
}

.btn-remove {
    position: absolute;
    top: 0.75rem;
    right: 0.75rem;
    background: none;
    border: 1px solid #e74c3c;
    color: #e74c3c;
    padding: 0.25rem 0.6rem;
    border-radius: 4px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: all 0.2s;
}

.btn-remove:hover {
    background: #e74c3c;
    color: #fff;
}

/* ── Buttons ── */
.step-actions {
    display: flex;
    justify-content: space-between;
    margin-top: 1.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid #eee;
}

.btn {
    padding: 0.65rem 1.5rem;
    border-radius: 6px;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.2s;
    border: none;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-primary {
    background: #4361ee;
    color: #fff;
    margin-left: auto;
}

.btn-primary:hover:not(:disabled) {
    background: #3a56d4;
}

.btn-outline {
    background: #fff;
    border: 1px solid #ccc;
    color: #444;
}

.btn-outline:hover {
    background: #f5f5f5;
}

.btn-secondary {
    background: #fff;
    border: 1px dashed #aaa;
    color: #555;
    padding: 0.5rem 1rem;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    margin-bottom: 0.5rem;
}

.btn-secondary:hover {
    border-color: #4361ee;
    color: #4361ee;
}

.btn-submit {
    padding: 0.75rem 2rem;
    font-size: 1rem;
}

.btn-link {
    background: none;
    border: none;
    color: #4361ee;
    cursor: pointer;
    font-size: 0.85rem;
    text-decoration: underline;
    padding: 0;
}

.btn-link:hover {
    color: #3a56d4;
}

/* ── Cover Letter ── */
.cover-letter-textarea {
    width: 100%;
    resize: vertical;
    min-height: 200px;
    font-family: inherit;
}

.char-count {
    text-align: right;
    font-size: 0.8rem;
    color: #888;
    margin-top: 0.3rem;
}

.char-count.over-limit {
    color: #e74c3c;
    font-weight: 600;
}

/* ── Review ── */
.review-section {
    border: 1px solid #e8e8e8;
    border-radius: 8px;
    padding: 1.25rem;
    margin-bottom: 1rem;
    background: #fafafa;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.review-header h3 {
    margin: 0;
    font-size: 1.05rem;
    color: #1a1a2e;
}

.review-details {
    display: grid;
    grid-template-columns: 120px 1fr;
    gap: 0.3rem 1rem;
    margin: 0;
}

.review-details dt {
    font-weight: 500;
    color: #666;
    font-size: 0.9rem;
}

.review-details dd {
    margin: 0;
    font-size: 0.9rem;
}

.review-entry {
    padding: 0.5rem 0;
    font-size: 0.9rem;
}

.review-entry + .review-entry {
    border-top: 1px solid #eee;
}

.review-dates {
    color: #888;
    font-size: 0.85rem;
}

.review-description {
    color: #555;
    font-size: 0.85rem;
    margin: 0.3rem 0 0;
}

.review-cover-letter {
    white-space: pre-wrap;
    font-size: 0.9rem;
    color: #444;
    margin: 0;
}

/* ── Confirmation ── */
.confirmation {
    text-align: center;
    padding: 3rem 1rem;
}

.confirmation-icon {
    width: 64px;
    height: 64px;
    border-radius: 50%;
    background: #2dc653;
    color: #fff;
    font-size: 2rem;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 1.5rem;
}

.confirmation h3 {
    font-size: 1.5rem;
    color: #1a1a2e;
    margin-bottom: 0.5rem;
}

.confirmation p {
    color: #666;
    font-size: 1rem;
}

